||@js:
return ad(result)
function ad(str) {
    let arr = [
        /.*?向你推荐他的其他作品：.*?/gi, 
        /希望你也喜欢.*/gi,
        /已改网址.*群号/gi,
        /\：，/gi,
        /.想看.*?完整章节/gi,
    ]
    for (let i in arr) {
        str = str.replace(arr[i], "")
    }
    return str
}

